async (params, browser) => {
  // Open Spotify artist page
  await browser.open(`${params.artist_url}`)

  // Wait for artist page to load
  await browser.waitForSelector('[data-testid="artist-header"], .artist-header, [data-testid="entityTitle"], h1', 15000)

  // Let artist page fully render
  await browser.wait(2500)

  // Extract artist information
  const artist_data = await browser.evaluate(`const nameEl = document.querySelector('[data-testid="entityTitle"] h1, [data-testid="artist-header"] h1, h1 span, h1'); const artistName = nameEl ? nameEl.textContent.trim() : ''; let monthlyListeners = ''; const listenersEl = document.querySelector('[data-testid="monthly-listeners"], .monthly-listeners'); if (listenersEl) { monthlyListeners = listenersEl.textContent.trim(); } else { const allSpans = document.querySelectorAll('span'); for (const s of allSpans) { if (s.textContent.match(/monthly listener/i)) { monthlyListeners = s.textContent.trim(); break; } } } const topTracks = []; const trackRows = document.querySelectorAll('[data-testid="tracklist-row"]'); for (let i = 0; i < Math.min(trackRows.length, 10); i++) { const row = trackRows[i]; const trackNameEl = row.querySelector('[data-testid="internal-track-link"] div, [data-testid="internal-track-link"], a[href^="/track"] div'); const playsEl = row.querySelector('span.encore-text'); let plays = ''; const allSpans = row.querySelectorAll('span.encore-text'); for (const s of allSpans) { if (s.textContent.match(/^[\d,\.]+$/)) { plays = s.textContent.trim(); break; } } let duration = ''; for (const s of allSpans) { if (s.textContent.match(/^\d+:\d+$/)) { duration = s.textContent.trim(); break; } } topTracks.push({ position: i + 1, name: trackNameEl ? trackNameEl.textContent.trim() : '', plays: plays, duration: duration }); } const releases = []; const releaseCards = document.querySelectorAll('section a[href^="/album"]'); const seenReleases = new Set(); for (let i = 0; i < Math.min(releaseCards.length, 10); i++) { const card = releaseCards[i]; const title = card.textContent.trim(); if (title && !seenReleases.has(title)) { seenReleases.add(title); releases.push({ title: title, link: card.href || '' }); } } return { artist_name: artistName, monthly_listeners: monthlyListeners, top_tracks_count: topTracks.length, top_tracks: topTracks, popular_releases_count: releases.length, popular_releases: releases }`)

  return artist_data
}
